var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아우드라...? 그게 누구이옵니까?","JPN":"アウドラ……？　それは誰のことでしょうか？","ENG":"Audra...? Who is that?","TWN":"奧德拉……？那是誰？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"怎樣？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"넌 모르는 거야? 저 여자에 대해서?","JPN":"知らないの？　あの女のこと。","ENG":"You don't know? Who she is?","TWN":"你不認識她？有關她的一切？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...예.","JPN":"……はい。","ENG":"...No.","TWN":"……是。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"모르는 게 당연해요.","JPN":"知らなくて当然です。","ENG":"It's only natural you wouldn't know.","TWN":"不知道也很正常。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"전 지금껏 누구의 눈에도 띄지 않고 지내왔거든요.","JPN":"今まで誰の目にも触れずに過ごしてきましたから。","ENG":"I've lived all this time without ever drawing anyone's notice.","TWN":"我一直都生活在不引人注意的地方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"누구의 눈에도 띄지 않다니... 낙원에선 누구도 숨을 필요 없습니다.","JPN":"誰の目にも触れないだなんて……楽園では誰も隠れる必要などありません。","ENG":"Without drawing anyone's notice... In the Promised Land, no one has any need to hide.","TWN":"不引人注意……在樂園裡，不需要躲避任何人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"부디 제 손을 잡으소서.","JPN":"どうかわたくしの手をお取りください。","ENG":"Please, take my hand.","TWN":"請握住我的手。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신은 변함없이 좋은 분이네요, 예하.","JPN":"あなたは相変わらず優しい方ですね、猊下。","ENG":"You are as kind as ever, Your Eminence.","TWN":"你依舊是個好人呢，主教。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...예하?","JPN":"……猊下？","ENG":"...Your Eminence?","TWN":"……主教？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"물러서, 에클레시아!","JPN":"下がって、エクレシア！","ENG":"Step back, Ecclesia!","TWN":"退後，艾可露西亞！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"위험해. 저 녀석이 타기리온이라고!","JPN":"危ない。あいつがタギリオンなんだよ！","ENG":"She's dangerous. She is Thagirion!","TWN":"危險，那傢伙就是塔基里翁！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저 소녀가 마왕...?","JPN":"あの少女が魔王……？","ENG":"That girl is a Demon Lord...?","TWN":"那個少女是魔王……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"하지만, 제가 들었던 모습과는 너무 다르온데...","JPN":"ですが、わたくしが聞いていた姿とはかけ離れております……","ENG":"But she looks nothing like what I had heard...","TWN":"可是她看起來和我聽說的完全不同……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"겉모습에 속아선 안돼. 우릴 기만하려는 거야.","JPN":"外見に騙されちゃダメ。私たちを欺こうとしてるんだ。","ENG":"Don't be fooled by appearances. She's trying to deceive us.","TWN":"別被外表騙了，她只是想騙過我們。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"목적을 밝혀!","JPN":"何が目的だ！","ENG":"State your purpose!","TWN":"說出你的目的！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"날 왜 여기로 데려왔는지. 이 낙원이라는 곳은 대체 뭔지!","JPN":"どうして私をここに連れてきたのか、この楽園という場所はいったい何なのか！","ENG":"Why did you bring me here? And what exactly is this place called the Promised Land?!","TWN":"為什麼把我帶到這裡，這個樂園到底是什麼地方！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"타기리온은 이곳에 없으니 걱정 마세요.","JPN":"タギリオンはここにいません。心配しないでください。","ENG":"Thagirion is not here, so there's no need to worry.","TWN":"塔基里翁不在這裡，你不用擔心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그녀의 숨이 붙어있는 한, 낙원에 발 들이지 않기로... 함께 약속했거든요.","JPN":"彼女が生きている限り、楽園に足を踏み入れないことを……一緒に約束しましたから。","ENG":"As long as she still draws breath, she promised... never to set foot in the Promised Land.","TWN":"我們曾約定……只要她還活著，就不會踏入樂園一步。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐...?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그게 무슨 소리지? 그 모습을 하고 있다 해서, 네가 타기리온과 다른 존재라도 된다는 거야?","JPN":"どういうこと？　その姿をしてるからって、君がタギリオンとは違う存在だとでも言いたいの？","ENG":"What is that supposed to mean? Just because you look like that, are you saying you're somehow a different being from Thagirion?","TWN":"你在說什麼？難道你的意思是就算你長這樣，也不是塔基里翁？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"맞아요.","JPN":"そのとおりです。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"타기리온이 마왕이 되기 위해 먼저 했던 일은... 가장 나약한 부분을 도려내는 일이었거든요.","JPN":"タギリオンが魔王になるために最初にやったことは……一番弱い部分をえぐり出すことでしたから。","ENG":"The first thing Thagirion did to become a Demon Lord... was cut away the weakest part of herself.","TWN":"塔基里翁為了成為魔王最先做的事……就是切除自己最軟弱的部分。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"가장... 나약한 부분이라고?","JPN":"一番……弱い部分？","ENG":"The weakest... part?","TWN":"最……軟弱的部分？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"저는 마왕이 되지 못한 그녀의 일부. 그녀가 두고 떠난 마음이에요.","JPN":"私は魔王になれなかった彼女の一部。彼女が置き去りにした心です。","ENG":"I am the part of her that could not become a Demon Lord. The heart she left behind.","TWN":"我是她沒能成為魔王的那一部分，我是她留下的心。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"사람을 잡아먹는 괴물에게 사람의 마음 같은 건 필요 없으니까.","JPN":"人を食らう化け物に、人の心なんて要りませんから。","ENG":"A monster that devours people has no need for a human heart.","TWN":"因為吞噬人類的怪物，不需要人類的心臟。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"당신이... 마왕 타기리온의 마음...?","JPN":"あなたが……魔王タギリオンの心……？","ENG":"You're... the heart of Demon Lord Thagirion...?","TWN":"你是……魔王塔基里翁的心？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"소녀는 본래 마왕이 될 운명이었어요.","JPN":"少女は最初から魔王になる運命でした。","ENG":"The girl was originally fated to become a Demon Lord.","TWN":"那個少女本來就注定會成為魔王。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그걸 거스르려다가... 너무 많은 희생을 불러왔죠.","JPN":"それに抵抗しようとして……あまりにも多くの犠牲を引き起こしました。","ENG":"In trying to defy that... she brought about far too many sacrifices.","TWN":"她試圖違抗命運……結果導致太多犧牲。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"우린 지금 그 대가를 치르고 있는 거에요.","JPN":"私たちは今まさに、その代償を払っているところなのです。","ENG":"And now we are paying the price for it.","TWN":"而我們現在正在承受那份代價。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"대가를 치른다니?","JPN":"代償を払うって？","ENG":"Paying the price?","TWN":"承受代價？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온은 지금도 멀쩡히 사람들을 유린하며 세계를 파괴하고 있어!","JPN":"タギリオンは今も人々を踏みにじりながら世界を破壊しているんだよ！","ENG":"Thagirion is still trampling people and destroying worlds without a care!","TWN":"塔基里翁現在仍在踐踏人類、破壞世界！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 반쪽이라는 넌 낙원이란 곳에서 이렇게 숨어있을 뿐인데, 무슨 대가를 치른다는 거지?","JPN":"その片割れだという君は楽園という場所にこうやって隠れてるだけなのに、何の代償を払ってるっていうの？","ENG":"And you, the so-called other half, are just hiding here in the Promised Land like this. What price are you possibly paying?","TWN":"而身為半個她的你，卻只會躲在這個叫樂園的地方。這算什麼代價？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...언젠가 말하고 싶었던 게 있어요, 네퀴티아.","JPN":"……いつか話したかったことがあります、ネキティア。","ENG":"...There's something I've wanted to say to you someday, Nequitia.","TWN":"……有句話我一直想對你說，莉奎蒂亞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신들의 단원들을 해쳤던 건 미안해요.","JPN":"あなたの団員を苦しめたこと、ごめんなさい。いつかこれを伝えたかったんです。","ENG":"I'm sorry for what happened to your orchestra members. I've wanted to say that someday.","TWN":"我一直想對你說，很抱歉傷害了你們團員。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"웃기지 마.","JPN":"ふざけないで。","ENG":"Don't make me laugh.","TWN":"別開玩笑了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"마에스트로 네퀴티아는 끔찍한 악행을 저지른 죄인이야. 그 여잘 따르던 단원들 역시 마찬가지고.","JPN":"マエストロ・ネキティアは酷い悪行を犯してきた罪人だよ。あの女に従っていた団員も同じ。","ENG":"Maestra Nequitia is a sinner who committed unforgivable atrocities. The orchestra members who followed her were no different.","TWN":"指揮家．莉奎蒂亞是犯下無數惡行的罪人，追隨她的團員也是一樣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"악인이 악인에게 사과를 한다고 해서, 무슨 변화라도 기대하는 건가?","JPN":"悪人が悪人に謝って、何かが変わるとでも思ってるの？","ENG":"Do you really expect anything to change just because one evil person apologizes to another?","TWN":"惡人向惡人道歉，就期待會有什麼改變嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"아뇨. 변하는 건 아무것도 없어요.","JPN":"いいえ。何も変わりはしません。","ENG":"No. Nothing changes.","TWN":"不，什麼都不會改變。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"엘리시온의 일원이던 당신의 단원들 역시, 이곳 낙원의 주민으로 살아가고 있으니까요.","JPN":"エリシオンの一員だったあなたの団員もまた、この楽園の住民として生きていますから。","ENG":"Your members from Elysion are also living here in the Promised Land as its residents.","TWN":"因為你那些曾屬於艾利森的團員，現在也是這個樂園的居民。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐...?","JPN":"は……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 악인들이 이런 곳에서 멀쩡히 살고 있다고?","JPN":"あの悪人たちがこんなところでのうのうと生きてるだって？","ENG":"Those villains are living peacefully in a place like this?","TWN":"那些罪人……在這裡活得好好的？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"대체 왜?","JPN":"いったいどうして？","ENG":"Why?","TWN":"為什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원은 그 누구도 차별하지 않아요.","JPN":"楽園は誰かを差別したりしません。","ENG":"The Promised Land does not discriminate against anyone.","TWN":"樂園不會歧視任何人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"세계가 선과 악 모두에게 공정한 기회를 베푼 것처럼.","JPN":"世界が善と悪の両方に同等な機会を与えてくれるように。","ENG":"Just as the world offers a fair chance to both good and evil.","TWN":"就像世界給予善惡同樣公平的機會一樣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"모든 것이 끝나기 전에, 모든 것을 매듭 지을 기회를 주는 것 뿐이죠.","JPN":"すべてが終わる前に、すべてに決着をつける機会を与えてくれるだけです。","ENG":"It merely gives everyone a chance to tie up all loose ends before everything comes to an end.","TWN":"在一切結束前，讓一切都有機會劃上句點。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"모든 것이 끝나기 전...?","JPN":"すべてが終わる前に……？","ENG":"Before everything comes to an end...?","TWN":"在一切結束前……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"여기 있었구나, 아우드라.","JPN":"ここにいたのか、アウドラ。","ENG":"So this is where you were, Audra.","TWN":"原來你在這裡啊，奧德拉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저 사람은...?","JPN":"あの人は……？","ENG":"Who is that...?","TWN":"那個人是……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저게... 어떻게 된 거지?","JPN":"あれは……どうなってるの？","ENG":"What... is going on here?","TWN":"這是怎麼回事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...기다리고 있었어요.","JPN":"……待っていました。","ENG":"...I've been waiting.","TWN":"……我一直在等你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"좀 더 일찍 결단을 내렸어야 했는데, 너무 늦어버린 나의 불찰이구나.","JPN":"もっと早く決断すべきだったが、遅くなりすぎてしまった我の不覚だ。","ENG":"I should have made my decision sooner, but my hesitation made me too late.","TWN":"我本來該更早做出決定，是我太慢了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"아뇨. 해는 아직 저물지 않은 걸요.","JPN":"いいえ。まだ日は暮れていません。","ENG":"No. The sun has not set yet.","TWN":"不，太陽還沒有落下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"늦지 않았어요. 이번에도.","JPN":"まだ間に合います。今回も。","ENG":"It's not too late. Not this time either.","TWN":"這次也不算晚。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"이렇게 할 수 밖에 없는 나를, 원망하거라.","JPN":"こうするしかない我を、恨むといい。","ENG":"Resent me, for being left with no choice but this.","TWN":"怨恨只能這麼做的我吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"원망하지 않아요.","JPN":"恨んだりしません。","ENG":"I don't resent you.","TWN":"我不恨你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"언제까지나.","JPN":"これからもずっと。","ENG":"Not now. Not ever.","TWN":"永遠不會。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저건, 칼?","JPN":"あれは、剣？","ENG":"Is that... a sword?","TWN":"那是……劍？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아, 물러서!","JPN":"エクレシア、下がって！","ENG":"Ecclesia, get back!","TWN":"艾可露西亞，退後！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"narration","speaker":null,"text":{"KOREA":"맞서야 할 적이라 생각했던 소녀는... 품은 각오가 무색할 정도로 간단히 쓰러졌다.","JPN":"立ち向かうべき敵だと思っていた少女は……胸に抱いた覚悟が虚しくなるほどあっさり倒れてしまった。","ENG":"The girl I had thought was the enemy we needed to face... fell with absurd ease, making my resolve seem meaningless.","TWN":"原以為必須對抗的少女……卻輕易地倒下了。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"뜻밖의 존재가 휘두른 검 앞에, 한 치 저항할 기색조차 없이.","JPN":"予想外の存在が振り回す剣の前に、少しも抵抗する様子もなく。","ENG":"Before a blade wielded by an utterly unexpected figure, she showed not even the slightest sign of resistance.","TWN":"意料之外的存在站在落下的劍前，甚至沒有絲毫抵抗。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"작은 에클레시아를 감싸려던 난, 뒷걸음치는 대신 그녀의 눈을 가렸다.","JPN":"小さいエクレシアを庇おうとした私は、後ずさりする代わりに彼女の視線を遮った。","ENG":"As I moved to shield little Ecclesia, instead of stepping back, I covered her eyes.","TWN":"原本想保護小小艾可露西亞的我，沒有選擇後退，而是遮住了她的眼睛。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 이내, 나 역시 잠시 눈을 감았다.","JPN":"そして、私もまた目を閉じた。","ENG":"And then, before long, I too closed my eyes for a moment.","TWN":"然後我自己也閉上了雙眼。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"악인의 최후라기엔 그 널브러진 모습이 너무나 참혹하면서도... 볼품없었기에.","JPN":"悪人の最期にしては、その力なく倒れた姿があまりにも残酷で……惨めだったから。","ENG":"For a villain's end, the way she lay there was far too miserable... and pathetically small.","TWN":"若說那就是惡人的結局，倒在地上的樣子未免太淒慘……太可悲。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"옅게 헐떡이던 소녀가 마지막 숨을 뱉었을 때, 그녀를 베고 지나간 검은 남아있지 않았다.","JPN":"浅く喘いでいた少女が最後に息を吐いた時、彼女を斬った剣は消えていた。","ENG":"When the faintly gasping girl let out her final breath, the blade that had cut through her was nowhere to be seen.","TWN":"當少女吐出最後一口氣時，斬過她的劍已經不見了。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"마치 처음부터 없었던 것처럼.","JPN":"まるで最初から存在しなかったかのように。","ENG":"As though it had never existed in the first place.","TWN":"彷彿從一開始就不存在。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저기, 레아 님.","JPN":"あの、レア様。","ENG":"Um, Ms. Leah.","TWN":"那個，蕾亞小姐。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저분은... 죽은 것이옵니까?","JPN":"あの方は……亡くなったのでございすか？","ENG":"Is she... dead?","TWN":"那個人……死了嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"아무래도, 그런 것 같아.","JPN":"どうやら、そのようだね。","ENG":"It seems so.","TWN":"應該是吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원에서 살인을 저지르다니...","JPN":"楽園で殺人を犯すなんて……","ENG":"To commit murder in the Promised Land...","TWN":"竟然在樂園殺人……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"믿기지 않사옵니다.","JPN":"信じられません。","ENG":"I can't believe it.","TWN":"實在令人難以置信。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그래.","JPN":"……うん。","ENG":"...No.","TWN":"……嗯。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"나 역시 보고도 믿기지 않네.","JPN":"私も自分の目を疑うよ。","ENG":"Even having seen it myself, I can scarcely believe it.","TWN":"我也不敢相信。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"수많은 참상을 목격해온 눈이지만, 그 죽음은 통 낯설었다.","JPN":"数多くの惨状をこの目で見てきたけど、その死はどれとも違っていた。","ENG":"These eyes have witnessed countless horrors, and yet that death felt utterly unfamiliar.","TWN":"雖然我見過無數慘劇，但這樣的死亡卻格外陌生。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 그것을 가까이에서 살펴보려 했을 때,","JPN":"だからそれを近くで見ようとしたその瞬間、","ENG":"So when I tried to take a closer look at it,","TWN":"所以當我想走近查看時，"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"누군가 먼저 그 주검에 손을 올렸다.","JPN":"誰かが先にその死体に手を置いた。","ENG":"someone placed a hand on the corpse first.","TWN":"有人先把手放在了屍體上。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"다이나...?","JPN":"ダイナ……？","ENG":"Daina...?","TWN":"黛娜……？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"곧 해가 저물 거다.","JPN":"もうすぐ日が暮れる。","ENG":"The sun will be setting soon.","TWN":"太陽很快就要落下了。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"뒤로 물러서.","JPN":"後ろに下がれ。","ENG":"Step back.","TWN":"退後。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 꽃은... 뭐죠?","JPN":"その花は……何なの？","ENG":"That flower... what is it?","TWN":"那朵花是……？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"흰 서리 꽃이다.","JPN":"白い雪の花だ。","ENG":"It's a white frost flower.","TWN":"白霜花。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"꽃.","JPN":"花。","ENG":"The flower.","TWN":"花。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"불현듯, 잠든 친구를 위해 꽃을 따던 한 소녀의 모습이 떠오른다.","JPN":"ふと、眠っている友だちのために花を摘んでいたある少女の姿が思い出された。","ENG":"All at once, I remembered a little girl picking flowers for her sleeping friend.","TWN":"我忽然想起一個為了沉睡的朋友摘花的少女身影。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"흰 꽃을 주검 위에 내려놓은 다이나는 조금도 당혹스럽거나 심란해 하는 표정이 아니었다.","JPN":"白い花を死体の上に乗せたダイナの顔に、動揺したり乱れた様子は微塵もなかった。","ENG":"Daina, placing the white flower atop the corpse, showed not the slightest trace of confusion or distress.","TWN":"黛娜把白花放在屍體上，臉上沒有一絲慌亂或悲傷。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"그런 것을 그로니아에서도 본 적이 있었다.","JPN":"ああいう表情をグロニアでも見たことがある。","ENG":"I had seen that sort of look before in Gronia.","TWN":"我在格羅尼亞也見過那樣的表情。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"서글프지만 익숙해질 수 밖에 없는.","JPN":"切なくても、慣れるしか方法のない。","ENG":"Sorrowful, yet something one cannot help but grow used to.","TWN":"雖然悲傷，卻不得不習慣。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"수 백 개의 무덤을 거쳐 마지막 묘비 앞에 선, 살아남은 퇴역군인의 그 초연한 눈빛과 닮아있었다.","JPN":"数百に及ぶ墓を通り過ぎ最後の墓石の前に立つ、生き残った退役軍人のあの超然とした目に似ていた。","ENG":"It resembled the detached gaze of a surviving veteran standing before the last gravestone after passing hundreds of graves.","TWN":"那種看淡一切的眼神，就像是一名走過數百座墳墓、站在最終墓碑前的退役士兵。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신...","JPN":"あなた……","ENG":"Hey...","TWN":"你……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이런 일이 처음이 아니군요.","JPN":"こういうの、初めてじゃないのね。","ENG":"This isn't your first time seeing this, is it?","TWN":"原來這不是第一次。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"...그래.","JPN":"……ああ。","ENG":"...No.","TWN":"……嗯。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"하지만 처음일 적에도 슬퍼하진 않았어.","JPN":"だが、最初の時も悲しみはしなかった。","ENG":"But even the first time, I didn't grieve.","TWN":"但即使是第一次，我也不會悲傷。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"애초에 이건, 이 아이가 택한 길이니까.","JPN":"そもそもこれは、この子が選んだ道だからな。","ENG":"This was the path that child chose from the start.","TWN":"這本來就是這孩子選擇的路。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"감싸고 있던 작은 어깨가 들썩인다.","JPN":"抱いていた小さな肩が揺れる。","ENG":"The small shoulders in my arms tremble.","TWN":"我懷裡的小小肩膀微微顫抖。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"내 품에 파고든 가여운 금발의 소녀는 마치 죽음이라는 것을 처음 보는 듯 창백하게 질려 있었다.","JPN":"私の胸に抱かれている哀れな金髪の少女は、まるで死というものを初めて見るように青白くなっていた。","ENG":"The pitiful blond girl clinging to me had gone pale, as though she were seeing death for the very first time.","TWN":"那個撲進我懷裡的金髮少女，像是第一次見到死亡般臉色蒼白。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"누구보다 많은 죽음을 목도하고, 영겁의 세월 동안 복수를 꿈꿔왔던 이는...","JPN":"誰よりも多くの死を目撃し、永劫の時の中で復讐を夢見ていたその人は……","ENG":"The one who had witnessed more deaths than anyone, and dreamed of revenge throughout an eternity...","TWN":"曾見證無數死亡、在永恆歲月中夢想復仇的人……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"...이제 아무것도 모르는 어린 양이 되고 만 걸까.","JPN":"……今や何も知らない子羊になってしまったのだろうか。","ENG":"...had she now become nothing more than an innocent lamb who knew nothing at all?","TWN":"……如今卻成了什麼都不知道的小羔羊。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아는 여기에 있어요.","JPN":"エクレシアはここにいて。","ENG":"Ecclesia is here.","TWN":"艾可露西亞就在這裡。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇다면 저희가 방금 보았던 건 누구죠?","JPN":"だとすると、さっき私たちが見たのは誰なの？","ENG":"Then who was it we just saw?","TWN":"那我們剛剛看到的是誰？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"낙원은 모두의 소망을 이루어주지.","JPN":"楽園はみんなの願いを叶えてくれる。","ENG":"The Promised Land grants everyone's wishes.","TWN":"樂園會實現所有人的願望。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"네가 본 것 역시, 그 아이의 소망이다.","JPN":"お前が見たのもまた、あの子の願いだ。","ENG":"What you saw was also that child's wish.","TWN":"你看到的，也是那孩子的願望。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그런 식으로 죽는 게, 소망이라고?","JPN":"あんな風に死ぬのが、願い？","ENG":"To die like that is a wish?","TWN":"她希望那樣死去？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"대체 누가 그런 걸 바란다고...!","JPN":"いったい誰がそんなことを望むっていうの……！","ENG":"Who in the world could wish for something like that...?!","TWN":"到底誰會祈求那樣的事……！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"자신이 바라는 것에 타인의 이해 같은 건 필요 없지.","JPN":"自分が望むことに他人の理解なんていらない。","ENG":"What one desires does not require anyone else's understanding.","TWN":"人類渴望的東西，不需要他人的理解。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RITA_ANAP_NULL_NULL","text":{"KOREA":"소망이란 건 그런 거야.","JPN":"願いとはそういうものだ。","ENG":"That is what a wish is.","TWN":"願望本來就是如此。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"해가 저문다.","JPN":"日が暮れる。","ENG":"The sun is setting.","TWN":"太陽落下了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"마치 무거워진 눈꺼풀처럼, 샛노란 지평선 위로 어둠이 내려앉는다.","JPN":"まるで重くなった瞼のように、黄色い地平線の上に闇が迫る。","ENG":"Like heavy eyelids, darkness settles over the pale yellow horizon.","TWN":"如同沉重的眼皮，黑暗覆上金黃色的地平線。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"머잖아 밤이 올 것이다.","JPN":"もうすぐ夜が来るだろう。","ENG":"Night will come before long.","TWN":"夜晚很快就會降臨。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"이곳이... 평범한 세상이라면 말이다.","JPN":"ここが……普通の世界なら。","ENG":"If this were... an ordinary world, that is.","TWN":"如果這裡……是普通世界的話。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"방금까지 놓여있던 그 꽃은... 대체 어디...?","JPN":"さっきまで置かれていたあの花は……いったいどこに……？","ENG":"The flower that was lying there just now... where did it go...?","TWN":"剛才放在那裡的花……去哪了？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"왜 그러니?","JPN":"どうしたんだい？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"꼭두새벽부터 그렇게 놀란 모습은 처음 보는구나.","JPN":"早朝からそんなに驚いた様子は初めてだな。","ENG":"I've never seen you look so startled this early in the morning.","TWN":"我還是第一次看到你一大早就這麼驚慌。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지...?","JPN":"お父様……？","ENG":"Father...?","TWN":"父親……？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"내키지 않으면, 오늘은 기도하지 말고 집에서 쉬도록 하렴.","JPN":"気が向かないなら、今日はお祈りをせずに家で休みなさい。","ENG":"If you don't feel up to it, then don't pray today. Rest at home instead.","TWN":"如果不想去，今天就別祈禱，在家休息吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아우드라란 이름을 아시옵니까?","JPN":"アウドラという名前をご存じですか？","ENG":"Do you know the name Audra?","TWN":"您知道奧德拉這個名字嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아우드라는, 낙원이 가진 또 하나의 이름이란다.","JPN":"アウドラは、この楽園のもう一つの名前だよ。","ENG":"Audra is another name for the Promised Land itself.","TWN":"奧德拉，是樂園的另一個名字。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지께선 그분을 만나 뵌 적이 있사옵니까?","JPN":"お父様はあの方に会われたことがおありなのですか？","ENG":"Have you ever met her, Father?","TWN":"父親有見過她嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是啊。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"황금나무를 가꾸는 사제의 의무를 내게 맡긴 게, 바로 그녀였거든.","JPN":"黄金の木の手入れをするという司祭の義務を僕に任せたのが彼女だからね。","ENG":"She was the one who entrusted me with the duty of tending the Golden Tree.","TWN":"就是她把照料黃金樹的祭司職責交給我的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"네가 그 이름을 알게 됐다는 건, 우리의 비원이 실현될 날이 머지 않았다는 뜻일 테지.","JPN":"お前がその名を知るようになったということは、みんなの悲願が成就する日が近いという意味なのだろう。","ENG":"The fact that you have come to know that name must mean the day our long-cherished wish is fulfilled is drawing near.","TWN":"既然你知道了這個名字，就代表離我們願望實現的日子不遠了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"비원이라면...","JPN":"悲願というと……","ENG":"By long-cherished wish...","TWN":"願望是……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"황금나무의 예언이 곧 이뤄진다는 말씀이십니까?","JPN":"黄金の木の予言がもうすぐ叶うという意味ですか？","ENG":"Do you mean the prophecy of the Golden Tree is soon to come true?","TWN":"黃金樹的預言即將實現嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그러니 너도 대비하려무나.","JPN":"だからお前も備えなさい。","ENG":"So you too must prepare yourself.","TWN":"所以你也要做好準備。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"영원한 가을 끝에 완성된 낙원에서 우리가 맞게 될 첫 계절은, 차가운 겨울일 테니 말이야.","JPN":"永遠の秋の末に完成された楽園で迎える最初の季節は、冷たい冬だろうから。","ENG":"For the first season we shall face in the Promised Land, once it is completed at the end of eternal autumn... will be a cold winter.","TWN":"在永恆的秋天盡頭完成的樂園，我們將迎來的第一個季節是寒冷的冬天。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"황금나무로 가시려는 겁니까?","JPN":"黄金の木に行かれるのですか？","ENG":"Are you going to the Golden Tree?","TWN":"您要去黃金樹那裡嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"...원한다면 따라오렴.","JPN":"……来たいならついておいで。","ENG":"...Come along, if you wish.","TWN":"……如果你想去，就跟我來吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리의 낙원이 어떻게 지금의 모습을 유지할 수 있는지, 가르쳐줄 테니.","JPN":"楽園がどうやって今の姿を維持しているのか、教えてあげよう。","ENG":"I will show you how our Promised Land has been able to maintain its present form.","TWN":"我會告訴你為什麼我們的樂園能一直維持現在的樣子。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"여기란다.","JPN":"ここだよ。","ENG":"Here we are.","TWN":"就是這裡。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이곳이 황금나무의 아래에 있는 중추기관...","JPN":"ここが黄金の木の下にある中枢機関……","ENG":"This place beneath the Golden Tree is the core facility...","TWN":"這裡是黃金樹下的中樞機關……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...낙원의 심장.","JPN":"……楽園の心臓。","ENG":"...The heart of the Promised Land.","TWN":"……樂園的心臟。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아버지는 이곳에서 홀로 일을 하시던 것이옵니까?","JPN":"お父様はこの場所でたった一人でお仕事をされているのですか？","ENG":"Have you been working here alone all this time, Father?","TWN":"父親一直一個人在這裡工作嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"오랫동안 그래왔단다.","JPN":"長いことそうやってきたんだよ。","ENG":"For a very long time, yes.","TWN":"長久以來都是如此。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"황금나무가 뿌리를 통해 양분을 축적하고, 그 양분을 낙원에 퍼뜨릴 수 있도록 돕고 있었지.","JPN":"黄金の木が根からの養分を蓄え、その養分が楽園全体にいきわたるように手伝っている。","ENG":"I have been helping the Golden Tree store up nourishment through its roots, so that it can spread that nourishment throughout the Promised Land.","TWN":"我協助黃金樹透過根部積蓄養分，再把養分分散到整個樂園。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"뿌리가 양분을 축적하도록... 돕는다?","JPN":"根が養分を蓄えられるように……手伝う？","ENG":"Helping the roots... store nourishment?","TWN":"協助根部積蓄養分……？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"황금나무는 세계와 세계를 넘나들 수 있는 뿌리를 가지고 있어.","JPN":"黄金の木は、世界と世界を行き来できる根を持っている。","ENG":"The Golden Tree has roots that can cross from world to world.","TWN":"黃金樹的根能穿越不同世界。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그리고 이 동판은 황금나무를 인도하는 눈 역할을 하지.","JPN":"そしてこの銅板は黄金の木を導く目の役割をするんだ。","ENG":"And this copper plate serves as the eyes that guide the Golden Tree.","TWN":"而這塊銅板，就是黃金樹的眼睛。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"어떤 곳에 양분이 있으며 뿌리가 어디를 향해 뻗어나가야 하는지, 이 동판을 통해서 황금나무를 인도하는 거란다.","JPN":"どこに養分があり、根はどこに向かって行くべきなのか、この銅板を通じて黄金の木を導くのだよ。","ENG":"Through this copper plate, it guides the Golden Tree toward where nourishment lies and where its roots must extend.","TWN":"哪裡有養分、根應該往哪裡延伸，都是透過這塊銅板引導黃金樹。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이것이... 황금나무의 눈...","JPN":"これが……黄金の木の目……","ENG":"This is... the Golden Tree's eye...","TWN":"這就是……黃金樹的眼睛……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"하지만, 이 동판에 비치는 것들은 전부 메마른 땅 뿐이옵니다. 양분이라곤 없어 보이는데...","JPN":"ですが、この銅板に見えるのはすべて痩せた土地でございます。養分などないように見えますが……","ENG":"But everything reflected on this copper plate is nothing but barren land. It doesn't look as though there is any nourishment there...","TWN":"可是這上面倒映的地方全是荒地，看起來根本沒有養分……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"그곳은 한때 가능성으로 가득 찬 풍요로운 세계였어.","JPN":"そこはかつて可能性で満ちていた豊かな世界だった。","ENG":"That place was once a prosperous world overflowing with possibility.","TWN":"那裡曾經是充滿可能性的富饒世界。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"황금나무의 뿌리가 이 세계의 가능성을 모두 우리의 낙원으로 흡수했기 때문에, 이렇게 메마르고 말았지.","JPN":"黄金の木の根がこの世界の可能性をすべて楽園に吸収したせいで、こうして痩せてしまったんだ。","ENG":"It became so barren because the roots of the Golden Tree absorbed every possibility in that world into our Promised Land.","TWN":"只是黃金樹的根將那個世界的所有可能性吸收至樂園，所以才會變成現在這樣的荒地。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"어째서 그런 짓을...?!","JPN":"どうしてそんなことを……！？","ENG":"How could you do such a thing...?!","TWN":"為什麼要做這種事……？！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리의 세계는 타기리온의 손에 한 차례 종말을 겪었어.","JPN":"僕たちの世界はタギリオンの手によって一度終末を経験した。","ENG":"Our world once met its end at Thagirion's hands.","TWN":"我們的世界曾經被塔基里翁毀滅過一次。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"멸망한 세계가 지금의 풍요로운 모습을 되찾을 수 있었던 건, 다 그 덕분이란다.","JPN":"滅亡した世界が今の豊かな姿を取り戻せたのは、これのおかげなんだよ。","ENG":"The only reason this ruined world was able to regain its present abundance is because of that.","TWN":"能恢復成現在這樣的繁榮景象，都是多虧了這個。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"하지만 언제까지고 빼앗기만 해야 하는 건 아니야.","JPN":"だが、いつまでも奪い続けなければならないわけではない。","ENG":"But it cannot go on taking forever.","TWN":"但我們也不能永遠只靠奪取。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"우리의 낙원은 양분을 통해 점차 완성되고 있지.","JPN":"楽園は養分のおかげで次第に完成してきている。","ENG":"Our Promised Land is gradually being completed through that nourishment.","TWN":"樂園正透過那些養分逐漸完成。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"앞으로 하나의 세계만 더 흡수하면, 우리의 낙원은 완벽해질 거다.","JPN":"あと一つ、世界を吸収すれば楽園は完璧になる。","ENG":"Once it absorbs just one more world, our Promised Land will be made perfect.","TWN":"只要再吸收一個世界，樂園就會變得完美。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"삶과 죽음, 밤과 낮이 공존하며, 그 무엇도 빼앗을 필요 없고 시들 걱정도 없는...","JPN":"生と死、夜と昼が共存し、何も奪う必要がなく、枯れる心配もない……","ENG":"A place where life and death, night and day coexist, where nothing must be taken from another and nothing need fear withering...","TWN":"生與死、晝夜共存。不需要再奪取任何東西，也不用擔心枯萎。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"완벽한 낙원, 아나필리스가 되는 거야.","JPN":"完璧な楽園、アナピリスになるのだよ。","ENG":"It will become Anapilis, the perfect Promised Land.","TWN":"那將會是完美的樂園，阿納菲莉絲。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...말도 안되옵니다.","JPN":"……信じられません。","ENG":"...That can't be.","TWN":"……太過分了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"제가 아는 아버지께서 그런 짓을 할 리가...","JPN":"わたくしの知っているお父様がそんなことをなさるはずが……","ENG":"The father I know would never do such a thing...","TWN":"我認識的父親，不可能做出這種事……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온은 지금도 멀쩡히 사람들을 유린하며 세계를 파괴하고 있어!","JPN":"タギリオンは今も人々を踏みにじりながら世界を破壊しているんだよ！","ENG":"Thagirion is still trampling people and destroying worlds without a care!","TWN":"塔基里翁現在仍在踐踏人類、破壞世界！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 반쪽이라는 넌 낙원이란 곳에서 이렇게 숨어있을 뿐인데, 무슨 대가를 치른다는 거지?","JPN":"その片割れだという君は楽園という場所にこうやって隠れてるだけなのに、何の代償を払ってるっていうの？","ENG":"And you, the so-called other half, are just hiding here in the Promised Land like this. What price are you possibly paying?","TWN":"而身為半個她的你，卻只會躲在這個叫樂園的地方。這算什麼代價？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"......!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그 아우드라란 자가 바로 마왕 타기리온과 한통속인 악인일 것이옵니다!","JPN":"あのアウドラという者こそ魔王タギリオンと共謀している悪人のはずです！","ENG":"Then that one called Audra must be a villain in league with Demon Lord Thagirion!","TWN":"那個叫奧德拉的人，一定是和魔王塔基里翁同流合污的壞人！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그자가 아버질 속여 다른 세상을 멸망시키려고 그런 악행을 맡긴 것입니다!","JPN":"あの者がお父様を騙し、他の世界を滅亡させようとこのような悪行を任せたのです！","ENG":"She must have deceived Father and made him do these evil deeds to destroy other worlds!","TWN":"她欺騙了父親，讓父親毀滅其他世界！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"제가 찾아가서 그 진상을 묻겠나이다!","JPN":"わたくしが行って、その真相を問います！","ENG":"I will go find her and demand the truth!","TWN":"我要去找她問個清楚！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"네가 무엇을 하든, 나는 막지 않으마.","JPN":"お前が何をしようと、僕は止めはしない。","ENG":"Whatever you choose to do, I will not stop you.","TWN":"無論你要做什麼，我都不會阻止。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원은 결국 우리 모두의 소망을 이루어줄 테니.","JPN":"楽園は結局、みんなの願いを叶えてくれるからだ。","ENG":"In the end, the Promised Land will grant the wishes of us all.","TWN":"因為樂園最終會實現我們所有人的願望。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};